<?php
$pageTitle='Employee Contracts & Documents';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('employee_contracts');
$pdo=getDB();$employees=$pdo->query('SELECT * FROM '.table('employees').' ORDER BY first_name,last_name')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'contract');
    if($action==='document'){
      $upload=uploadAdminDocument('employee_file','employee-documents');if(!$upload){throw new RuntimeException('Choose a document file.');}
      createEmployeeDocument($pdo,(int)$_POST['employee_id'],$upload,trim((string)$_POST['document_type']),trim((string)$_POST['expiry_date']),trim((string)$_POST['notes']));
      flash('success','Employee document uploaded.');
    }else{
      $number=nextScopedDocumentNumber($pdo,'employee_contract',setting('employee_contract_prefix','ECON'),operationalScope($pdo));
      $pdo->prepare('INSERT INTO '.table('employee_contracts').' (contract_number,employee_id,contract_type,start_date,end_date,basic_salary,allowance_total,working_hours_per_day,working_days_per_month,status,notes) VALUES (?,?,?,?,?,?,?,?,?,"active",?)')->execute([$number,(int)$_POST['employee_id'],trim((string)$_POST['contract_type']),trim((string)$_POST['start_date'])?:null,trim((string)$_POST['end_date'])?:null,max(0,(float)$_POST['basic_salary']),max(0,(float)$_POST['allowance_total']),max(0,(float)$_POST['working_hours_per_day']),max(0,(float)$_POST['working_days_per_month']),trim((string)$_POST['notes'])]);
      flash('success','Employee contract created.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'employee-contracts']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/employee-contracts.php');
}
$contracts=$pdo->query('SELECT c.*,CONCAT(e.first_name," ",e.last_name) employee_name,e.employee_code FROM '.table('employee_contracts').' c LEFT JOIN '.table('employees').' e ON e.id=c.employee_id ORDER BY c.created_at DESC LIMIT 120')->fetchAll();
$docs=$pdo->query('SELECT d.*,CONCAT(e.first_name," ",e.last_name) employee_name,e.employee_code FROM '.table('employee_documents').' d LEFT JOIN '.table('employees').' e ON e.id=d.employee_id ORDER BY d.created_at DESC LIMIT 120')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Employee Master Data</div><h2 class="h4 mb-1">Contracts & Documents</h2><p class="text-secondary mb-0">Manage employee contracts, salary details, working rules, and HR files.</p></div></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Create Contract</h2><select class="form-select mb-2" name="employee_id"><?php foreach($employees as $e): ?><option value="<?php echo (int)$e['id']; ?>"><?php echo esc($e['employee_code'].' · '.$e['first_name'].' '.$e['last_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="contract_type" value="full_time"><div class="row g-2"><div class="col-6"><input class="form-control" type="date" name="start_date"></div><div class="col-6"><input class="form-control" type="date" name="end_date"></div></div><input class="form-control my-2" type="number" step="0.01" name="basic_salary" placeholder="Basic salary"><input class="form-control mb-2" type="number" step="0.01" name="allowance_total" placeholder="Allowance total"><div class="row g-2"><div class="col-6"><input class="form-control" type="number" step="0.01" name="working_hours_per_day" value="8"></div><div class="col-6"><input class="form-control" type="number" step="0.01" name="working_days_per_month" value="26"></div></div><textarea class="form-control my-3" name="notes" rows="2"></textarea><button class="btn btn-brand w-100">Create Contract</button></form><form method="post" enctype="multipart/form-data" class="card-admin p-4"><input type="hidden" name="action" value="document"><h2 class="h5 mb-3">Upload Document</h2><select class="form-select mb-2" name="employee_id"><?php foreach($employees as $e): ?><option value="<?php echo (int)$e['id']; ?>"><?php echo esc($e['employee_code'].' · '.$e['first_name'].' '.$e['last_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="document_type" placeholder="Passport, visa, contract, certificate"><input class="form-control mb-2" type="date" name="expiry_date"><input class="form-control mb-2" type="file" name="employee_file" required><textarea class="form-control mb-3" name="notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Upload</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Contracts</h2><table class="table"><thead><tr><th>Contract</th><th>Employee</th><th>Salary</th><th>Dates</th><th>Status</th></tr></thead><tbody><?php foreach($contracts as $c): ?><tr><td><strong><?php echo esc($c['contract_number']); ?></strong><div class="small text-secondary"><?php echo esc($c['contract_type']); ?></div></td><td><?php echo esc($c['employee_code'].' · '.$c['employee_name']); ?></td><td><?php echo money($c['basic_salary']+$c['allowance_total']); ?></td><td><?php echo esc($c['start_date'].' → '.$c['end_date']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['status'])); ?>"><?php echo esc($c['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Documents</h2><table class="table"><thead><tr><th>Employee</th><th>Document</th><th>Expiry</th><th>Status</th></tr></thead><tbody><?php foreach($docs as $d): ?><tr><td><?php echo esc($d['employee_code'].' · '.$d['employee_name']); ?></td><td><strong><?php echo esc($d['document_type']); ?></strong><div class="small text-secondary"><?php echo esc($d['file_name']); ?></div></td><td><?php echo esc($d['expiry_date']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($d['status'])); ?>"><?php echo esc($d['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>